import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        abs_dir = os.path.abspath(dir_path)
        file_path = os.path.join(abs_dir, filename)
        abs_file_path = os.path.abspath(file_path)
        if not abs_file_path.startswith(abs_dir):
            return ""
        with open(file_path, 'r') as f:
            return f.read()
    except:
        return ""

def store_info_in_header(info_type: str, info_content: str, header: Dict[str, str]) -> Dict[str, str]:
    valid_types = {'lang', 'encoding', 'cache'}
    if info_type not in valid_types:
        return header
    key_map = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    key = key_map[info_type]
    new_header = header.copy()
    new_header[key] = info_content
    return new_header

